Here's a C++ function that prints the cube of all numbers from 1 to n, satisfying the given conditions:

```cpp
#include <iostream>
#include <cmath>

bool isPrime(int num) {
    if (num <= 1)
        return false;

    for (int i = 2; i <= sqrt(num); i++) {
        if (num % i == 0)
            return false;
    }

    return true;
}

void printCubes(int n) {
    for (int i = 1; i <= n; i++) {
        if (isPrime(i) && i < 100 && i % 3 == 0) {
            int cube = i * i * i;
            std::cout << "Cube of " << i << " is " << cube << std::endl;
        }
    }
}

int main() {
    int n;
    std::cout << "Enter a positive integer: ";
    std::cin >> n;

    printCubes(n);

    return 0;
}
```

