```html
<!DOCTYPE html>
<html>
<head>
    <title>Table with Odd Row Background Color</title>
    <style>
        table {
            border-collapse: collapse;
        }

        td {
            border: 1px solid black;
            padding: 10px;
        }
    </style>
</head>
<body>
    <table id="myTable">
        <tr>
            <td>Cell 1</td>
            <td>Cell 2</td>
            <td>Cell 3</td>
        </tr>
        <tr>
            <td>Cell 4</td>
            <td>Cell 5</td>
            <td>Cell 6</td>
        </tr>
        <tr>
            <td>Cell 7</td>
            <td>Cell 8</td>
            <td>Cell 9</td>
        </tr>
    </table>

    <script>
        var table = document.getElementById("myTable");
        var rows = table.getElementsByTagName("tr");

        for (var i = 0; i < rows.length; i++) {
            var cells = rows[i].getElementsByTagName("td");
            var isOddRow = i % 2 === 0;

            for (var j = 0; j < cells.length; j++) {
                var isOddCell = j % 2 === 0;

                if (isOddRow) {
                    cells[j].style.backgroundColor = isOddCell ? "lightblue" : "lightgreen";
                } else {
                    cells[j].style.backgroundColor = isOddCell ? "lightgreen" : "lightblue";
                }
            }
        }
    </script>
</body>
</html>
