```csharp
using System;
using System.Collections.Generic;
using System.Linq;

public class Program
{
    public static List<List<T>> GetCombinations<T>(T[] array, int n)
    {
        List<List<T>> combinations = new List<List<T>>();
        GenerateCombinations(array, n, new List<T>(), combinations);
        return combinations.OrderBy(c => string.Join("", c)).ToList();
    }

    private static void GenerateCombinations<T>(T[] array, int n, List<T> current, List<List<T>> combinations)
    {
        if (current.Count == n)
        {
            combinations.Add(current.ToList());
            return;
        }

        for (int i = 0; i < array.Length; i++)
        {
            current.Add(array[i]);
            GenerateCombinations(array, n, current, combinations);
            current.RemoveAt(current.Count - 1);
        }
    }

    public static void Main(string[] args)
    {
        int[] array = { 1, 2, 2, 3 };
        int n = 2;
        List<List<int>> combinations = GetCombinations(array, n);

        foreach (var combination in combinations)
        {
            Console.WriteLine(string.Join(", ", combination));
        }
    }
}
```

