public class ServiceHandler
{
    public static List<string> FilterRecords(List<string> records)
    {
        List<string> filteredRecords = new List<string>();

        foreach (string record in records)
        {
            if (IsPrime(record.Length) && ContainsReverseVowels(record))
            {
                filteredRecords.Add(record);
            }
        }

        return filteredRecords;
    }

    private static bool IsPrime(int number)
    {
        if (number <= 1)
            return false;

        for (int i = 2; i <= Math.Sqrt(number); i++)
        {
            if (number % i == 0)
                return false;
        }

        return true;
    }

    private static bool ContainsReverseVowels(string word)
    {
        int vowelCount = 0;
        char[] vowels = { 'a', 'e', 'i', 'o', 'u' };

        for (int i = word.Length - 1; i >= 0; i--)
        {
            if (vowels.Contains(Char.ToLower(word[i])))
            {
                vowelCount++;

                if (vowelCount >= 2)
                    return true;
            }
        }

        return false;
    }
}
```

