import math

class Point:
    def __init__(self, x, y):
        self.x = x
        self.y = y

    def distance_to_origin(self, power=2):
        if power == 2:
            return math.sqrt(self.x ** 2 + self.y ** 2)
        else:
            return (abs(self.x) ** power + abs(self.y) ** power) ** (1 / power)

    def translate(self, dx, dy, direction="both"):
        if direction == "x":
            self.x += dx
        elif direction == "y":
            self.y += dy
        else:
            self.x += dx
            self.y += dy

    def reflect(self):
        self.y = -self.y

    @staticmethod
    def create_point(x, y):
        return Point(x, y)
