```cpp
#include <iostream>
#include <vector>
#include <cmath>

class RollingAverage {
private:
    std::vector<double> data; // stream of numbers
    int windowSize; // size of the rolling window

public:
    RollingAverage(int size) {
        windowSize = size;
    }

    void addNumber(double num) {
        data.push_back(num);
        if (data.size() > windowSize) {
            data.erase(data.begin());
        }
    }

    double calculateRollingAverage() {
        double sum = 0;
        for (double num : data) {
            sum += num;
        }
        return sum / data.size();
    }

    double calculateStandardDeviation() {
        double mean = calculateRollingAverage();
        double sum = 0;
        for (double num : data) {
            sum += pow(num - mean, 2);
        }
        double variance = sum / data.size();
        return sqrt(variance);
    }

    void removeOutliers(double threshold) {
        double mean = calculateRollingAverage();
        double standardDeviation = calculateStandardDeviation();
        std::vector<double> newData;
        for (double num : data) {
            if (fabs(num - mean) <= threshold * standardDeviation) {
                newData.push_back(num);
            }
        }
        data = newData;
    }
};

int main() {
    RollingAverage ra(5);

    ra.addNumber(10);
    ra.addNumber(15);
    ra.addNumber(13);
    ra.addNumber(12);
    ra.addNumber(11);

    std::cout << "Rolling Average: " << ra.calculateRollingAverage() << std::endl;
    std::cout << "Standard Deviation: " << ra.calculateStandardDeviation() << std::endl;

    ra.removeOutliers(2.0);

    std::cout << "Rolling Average (after removing outliers): " << ra.calculateRollingAverage() << std::endl;
    std::cout << "Standard Deviation (after removing outliers): " << ra.calculateStandardDeviation() << std::endl;

    return 0;
}
```

In this class, the `RollingAverage` class is defined to store a stream of numbers and perform calculations such as calculating the rolling average and standard deviation. The constructor takes an argument `size` which determines the size of the rolling window.

The `addNumber()` method adds a number to the stream and keeps the window size limited by removing the oldest number if necessary.

The `calculateRollingAverage()` method calculates the average of the numbers in the stream.

The `calculateStandardDeviation()` method calculates the standard deviation of the numbers in the stream by first calculating the mean, then calculating the sum of the squared differences from the mean, and finally taking the square root of the variance.

The `removeOutliers()` method removes outliers from the stream by comparing each number with the mean and removing it if the absolute difference is greater than `threshold` times the standard deviation.

