One possible data structure in Python to store a list of countries and their capitals, where each country can have multiple capitals, is a dictionary where the keys are the countries and the values are lists of capitals. Here's an implementation with the required functions:

```python
class CountryCapitals:
    def __init__(self):
        self.data = {}

    def add_capital(self, country, capital):
        if country not in self.data:
            self.data[country] = []
        self.data[country].append(capital)

    def remove_capital(self, country, capital):
        if country in self.data and capital in self.data[country]:
            self.data[country].remove(capital)
            if len(self.data[country]) == 0:
                del self.data[country]

    def find_country(self, capital):
        countries = []
        for country, capitals in self.data.items():
            if capital in capitals:
                countries.append(country)
        return countries

    def find_capitals(self, country):
        if country in self.data:
            return self.data[country]
        return []

    def capital_exists(self, capital):
        for capitals in self.data.values():
            if capital in capitals:
                return True
        return False
```

