  const [error, setError] = useState('');
  const [zipcodeData, setZipcodeData] = useState(null);

  const handleInputChange = (event) => {
    setZipcode(event.target.value);
  };

  const fetchData = async () => {
    try {
      setLoading(true);
      const response = await fetch(`https://api.openweathermap.org/data/2.5/weather?zip=${zipcode},us&appid=YOUR_API_KEY`);
      const data = await response.json();
      setLoading(false);
      if (data.cod === '404') {
        setError('Zipcode not found');
      } else {
        setError('');
        setZipcodeData({
          city: data.name,
          state: data.sys.country,
          county: data.sys.country, // You can fetch county information from a different API if available
          latitude: data.coord.lat,
          longitude: data.coord.lon,
          population: data.population,
          timezone: data.timezone,
          areaCode: data.areaCode,
          attractions: data.attractions, // You can fetch attractions information from a different API if available
          weather: data.weather[0].description,
        });
      }
    } catch (error) {
      setLoading(false);
      setError('Error fetching zipcode information');
    }
  };

  useEffect(() => {
    if (zipcode.length === 5) {
      fetchData();
    } else {
      setZipcodeData(null);
    }
  }, [zipcode]);

  return (
    <div>
      <input type="text" value={zipcode} onChange={handleInputChange} />
      {loading && <div>Loading...</div>}
      {error && <div>Error: {error}</div>}
      {zipcodeData && (
