Here is a C program that checks if a sentence is a palindrome, considering all the given conditions:

```c
#include <stdio.h>
#include <ctype.h>
#include <stdbool.h>
#include <string.h>

bool isPalindrome(char *sentence, int start, int end) {
    // Base case: If start index is greater than or equal to end index, it's a palindrome
    if (start >= end) {
        return true;
    }

    // Ignore non-alphanumeric characters and convert to lowercase
    while (!isalnum(sentence[start])) {
        start++;
    }
    while (!isalnum(sentence[end])) {
        end--;
    }
    sentence[start] = tolower(sentence[start]);
    sentence[end] = tolower(sentence[end]);

    // Check if characters at start and end indexes are equal
    if (sentence[start] == sentence[end]) {
        return isPalindrome(sentence, start + 1, end - 1);
    } else {
        return false;
    }
}

int main() {
    char sentence[1000];

    printf("Enter a sentence: ");
    fgets(sentence, sizeof(sentence), stdin);

    // Remove trailing newline character
    if (sentence[strlen(sentence) - 1] == '\n') {
        sentence[strlen(sentence) - 1] = '\0';
    }

    if (isPalindrome(sentence, 0, strlen(sentence) - 1)) {
        printf("The sentence is a palindrome.\n");
    } else {
        printf("The sentence is not a palindrome.\n");
    }

    return 0;
}
```

This program prompts the user to enter a sentence, checks if it is a palindrome, and then displays the result. It uses a recursive function `isPalindrome()` to check if the sentence is a palindrome. The function uses two pointers, `start` and `end`, to check the characters at the corresponding positions. It ignores spaces and punctuation marks, converts characters to lowercase, and compares them recursively. The `main()` function takes care of input, removes the trailing newline character, and calls the `isPalindrome()` function.

