Here is a possible implementation in Python:

```python
import re
import json

def parse_html(html):
    def parse_attributes(tag):
        attributes = {}
        for match in re.findall(r'(\w+)\s*=\s*"(.*?)"', tag):
            attributes[match[0]] = match[1]
        return attributes

    def parse_tag(tag):
        if tag.startswith('<!--') and tag.endswith('-->'):
            return None  # Ignore comments

        match = re.match(r'<(\w+)(.*?)>(.*?)<\/\1>', tag)
        if match:
            tag_name = match.group(1)
            attributes = parse_attributes(match.group(2))
            value = match.group(3)
            return {
                '_attributes': attributes,
                '_value': value,
            }

        match = re.match(r'<(\w+)(.*?)\/>', tag)
        if match:
            tag_name = match.group(1)
            attributes = parse_attributes(match.group(2))
            return {
                '_attributes': attributes,
            }

    stack = []
    root = None

    for line in html.splitlines():
        match = re.search(r'<(\w+.*?)(\/?)>', line)
        if match:
            tag = match.group(0)
            if match.group(2) == '/':
                # Closing tag
                closed_tag = stack.pop()
                if not stack:
                    root = closed_tag
                else:
                    parent = stack[-1]
                    if isinstance(parent, dict):
                        parent['_value'] = parent.get('_value', '') + closed_tag['_value']
            else:
                # Opening tag
                parsed_tag = parse_tag(tag)
                if parsed_tag:
                    stack.append(parsed_tag)
                    parent = stack[-2] if len(stack) > 1 else None
                    if isinstance(parent, dict):
                        parent['_value'] = parent.get('_value', '') + tag

    return json.dumps(root, indent=2)

