<h1 class="heading">Hello <span style="color: red;">World!</span></h1>
<p>This is a paragraph with <a href="https://example.com">a link</a> and an image: <img src="image.jpg" alt="Image"></p>
</body>
</html>
'''

json_object = parse_html(html)
print(json_object)
