#!/usr/bin/perl

use strict;
use warnings;

sub remove_last_element {
    my @array = @_;

    my $array_size = scalar @array;

    # If the array is empty or contains only one element, return an empty array
    return [] if $array_size < 2;

    # Create a new array without the last element
