```python
def pig_latin(sentence):
    vowels = ['a', 'e', 'i', 'o', 'u']
    consonant_clusters = ['th', 'qu', 'sch']
    punctuation = ['.', ',', '?', '!', ':', ';']

    def convert_word(word):
        if word[0].isupper():
            is_capitalized = True
            word = word.lower()
        else:
            is_capitalized = False

        if word[0] in vowels:
            if word[:2] == 'th' and word[2] in vowels:
                word = word[2:] + word[:2] + 'ay'
            elif word[:2] == 'th':
                word = word[2:] + 'thay'
            elif word[:2] == 'qu':
                word = word[2:] + 'quay'
            elif word[:3] == 'sch':
                word = word[3:] + 'schay'
            else:
                word += 'way'
        else:
            if word[:2] == 'th' and word[2] in vowels:
                word = word[2:] + word[:2] + 'ay'
            elif word[:2] == 'th':
                word = word[2:] + 'thay'
            elif word[:2] == 'qu':
                word = word[2:] + 'quay'
            elif word[:3] == 'sch':
                word = word[3:] + 'schay'
            else:
                consonant_cluster = ''
                while word[0] not in vowels:
                    consonant_cluster += word[0]
                    word = word[1:]
                word += consonant_cluster + 'ay'

        if word[-1] in punctuation:
            word = word[:-1] + word[-1]

        if is_capitalized:
            word = word.capitalize()

        return word

    words = sentence.split()
    pig_latin_sentence = [convert_word(word) for word in words]
    return ' '.join(pig_latin_sentence)


