class Rectangle:
    def __init__(self, width: int, height: int):
        self.__width = width
        self.__height = height

    def get_width(self) -> int:
        return self.__width

    def get_height(self) -> int:
        return self.__height

    def get_area(self) -> float:
        return float(self.__width * self.__height)

    def get_perimeter(self) -> float:
        return float(2 * (self.__width + self.__height))

    def is_square(self) -> bool:
        return self.__width == self.__height

    def scale(self, factor: float) -> None:
        self.__width = round(self.__width * factor)
        self.__height = round(self.__height * factor)

    def rotate90(self) -> None:
        self.__width, self.__height = self.__height, self.__width

    def get_diagonal_length(self) -> float:
        return ((self.__width ** 2) + (self.__height ** 2)) ** 0.5

