```php
class Node {
    public $id;
    public $value;
    public $left;
    public $right;

    public function __construct($id, $value) {
        $this->id = $id;
        $this->value = $value;
        $this->left = null;
        $this->right = null;
    }
}

class Tree {
    public $root;

    public function __construct() {
        $this->root = null;
    }

    public function insert($id, $value, $position = null) {
        $node = new Node($id, $value);

        if ($this->root === null) {
            $this->root = $node;
        } else {
            $this->insertNode($node, $this->root, $position);
        }
    }

    private function insertNode($node, &$subtree, $position) {
        if ($subtree === null) {
            $subtree = $node;
        } else {
            if ($position === 'left') {
                $this->insertNode($node, $subtree->left, $position);
            } elseif ($position === 'right') {
                $this->insertNode($node, $subtree->right, $position);
            } else {
                $this->insertNode($node, $subtree->left, 'left');
                $this->insertNode($node, $subtree->right, 'right');
            }
        }
    }

    public function delete($id) {
        $this->root = $this->deleteNode($id, $this->root);
    }

    private function deleteNode($id, $subtree) {
        if ($subtree === null) {
            return $subtree;
        }

        if ($id < $subtree->id) {
            $subtree->left = $this->deleteNode($id, $subtree->left);
        } elseif ($id > $subtree->id) {
            $subtree->right = $this->deleteNode($id, $subtree->right);
        } else {
            if ($subtree->left === null) {
                return $subtree->right;
            } elseif ($subtree->right === null) {
                return $subtree->left;
            }

            $subtree->id = $this->minValue($subtree->right);
            $subtree->right = $this->deleteNode($subtree->id, $subtree->right);
        }

        return $subtree;
    }

    private function minValue($subtree) {
        $minValue = $subtree->id;
        while ($subtree->left !== null) {
            $minValue = $subtree->left->id;
            $subtree = $subtree->left;
        }
        return $minValue;
    }

    public function search($id) {
        return $this->searchNode($id, $this->root);
    }

    private function searchNode($id, $subtree) {
        if ($subtree === null || $subtree->id === $id) {
            return $subtree;
        }

        if ($id < $subtree->id) {
            return $this->searchNode($id, $subtree->left);
        } else {
            return $this->searchNode($id, $subtree->right);
        }
    }

    public function preOrderTraversal($subtree = null) {
        if ($subtree === null) {
            $subtree = $this->root;
        }

        if ($subtree !== null) {
            echo $subtree->id . ' ';
            $this->preOrderTraversal($subtree->left);
            $this->preOrderTraversal($subtree->right);
        }
    }

    public function inOrderTraversal($subtree = null) {
        if ($subtree === null) {
            $subtree = $this->root;
        }

        if ($subtree !== null) {
            $this->inOrderTraversal($subtree->left);
            echo $subtree->id . ' ';
            $this->inOrderTraversal($subtree->right);
        }
    }

    public function postOrderTraversal($subtree = null) {
        if ($subtree === null) {
            $subtree = $this->root;
        }

        if ($subtree !== null) {
            $this->postOrderTraversal($subtree->left);
            $this->postOrderTraversal($subtree->right);
            echo $subtree->id . ' ';
        }
    }
}

