Sure! Here's an example of how you can create a React web page that generates a word cloud based on the frequency of words in a text file. The word cloud will also allow the user to filter out common stop words and specify the maximum number of words to be displayed.

First, let's set up the project and install the necessary dependencies. Open your terminal and run the following commands:

```shell
npx create-react-app word-cloud-app
cd word-cloud-app
npm install d3-cloud stopwords react-wordcloud
```

Now, let's create the necessary components. Replace the content of `src/App.js` with the following code:

```jsx
import React, { useState } from 'react';
import WordCloud from 'react-wordcloud';
import stopwords from 'stopwords';
import './App.css';

const App = () => {
  const [text, setText] = useState('');
  const [filteredText, setFilteredText] = useState('');
  const [maxWords, setMaxWords] = useState(50);

  const handleTextChange = (event) => {
    setText(event.target.value);
  };

  const handleFilterChange = (event) => {
    setFilteredText(event.target.value);
  };

  const handleMaxWordsChange = (event) => {
    setMaxWords(Number(event.target.value));
  };

  const generateWordCloudData = () => {
    const wordCountMap = {};

    // Split text into words
    const words = text.split(/\s+/);

    // Count frequency of each word
    words.forEach((word) => {
      const lowercaseWord = word.toLowerCase();
      if (!stopwords.includes(lowercaseWord)) {
        if (wordCountMap[lowercaseWord]) {
          wordCountMap[lowercaseWord]++;
        } else {
          wordCountMap[lowercaseWord] = 1;
        }
      }
    });

    // Convert word count map into an array of objects
    const wordCloudData = Object.keys(wordCountMap).map((word) => ({
      text: word,
      value: wordCountMap[word],
    }));

    // Sort word cloud data by frequency
    wordCloudData.sort((a, b) => b.value - a.value);

    // Return a subset of word cloud data based on the max words setting
    return wordCloudData.slice(0, maxWords);
  };

  return (
    <div className="App">
      <h1>Word Cloud Generator</h1>
      <div className="controls">
        <div className="form-group">
          <label htmlFor="textInput">Enter text:</label>
          <textarea
            id="textInput"
            value={text}
            onChange={handleTextChange}
          ></textarea>
        </div>
        <div className="form-group">
          <label htmlFor="filterInput">Filter out words:</label>
          <input
            id="filterInput"
            type="text"
            value={filteredText}
            onChange={handleFilterChange}
          />
        </div>
        <div className="form-group">
          <label htmlFor="maxWordsInput">Max words:</label>
          <input
            id="maxWordsInput"
            type="number"
            min="1"
            value={maxWords}
            onChange={handleMaxWordsChange}
          />
        </div>
      </div>
      <div className="word-cloud">
        <WordCloud
          words={generateWordCloudData()}
          options={{ fontFamily: 'sans-serif', fontSizes: [10, 60] }}
        />
      </div>
    </div>
  );
};

export default App;
```

