#include <stdio.h>

int isPalindrome(int num) {
    int reversed = 0;
    int original = num;

    // Reverse the number
    while (num > 0) {
        int remainder = num % 10;
        reversed = reversed * 10 + remainder;
        num = num / 10;
    }

    // Check if the reversed number is equal to the original number
    if (reversed == original) {
        return 1;
    } else {
        return 0;
    }
}

int main() {
