Here's a C# program that removes all occurrences of an item from an array, including multi-dimensional arrays, in-place without creating a new array:

```csharp
using System;

class Program
{
    static void Main(string[] args)
    {
        // Test with a one-dimensional array
        int[] arr1 = { 1, 2, 3, 4, 2, 5, 2 };
        Console.WriteLine("Original array:");
        PrintArray(arr1);
        RemoveAllOccurrences(ref arr1, 2);
        Console.WriteLine("After removing all occurrences of 2:");
        PrintArray(arr1);

        // Test with a two-dimensional array
        int[,] arr2 = { { 1, 2, 3 }, { 4, 2, 5 }, { 2, 6, 7 } };
        Console.WriteLine("Original array:");
        PrintArray(arr2);
        RemoveAllOccurrences(ref arr2, 2);
        Console.WriteLine("After removing all occurrences of 2:");
        PrintArray(arr2);
    }

    static void RemoveAllOccurrences(ref int[] arr, int item)
    {
        int i = 0;
        int n = arr.Length;

        for (int j = 0; j < n; j++)
        {
            if (arr[j] != item)
            {
                arr[i] = arr[j];
                i++;
            }
        }

        Array.Resize(ref arr, i);
    }

    static void RemoveAllOccurrences(ref int[,] arr, int item)
    {
        int rowCount = arr.GetLength(0);
        int colCount = arr.GetLength(1);

        for (int i = 0; i < rowCount; i++)
        {
            int[] row = new int[colCount];
            int newRowLength = 0;

            for (int j = 0; j < colCount; j++)
            {
                if (arr[i, j] != item)
                {
                    row[newRowLength] = arr[i, j];
                    newRowLength++;
                }
            }

            Array.Resize(ref row, newRowLength);

            for (int j = 0; j < newRowLength; j++)
            {
                arr[i, j] = row[j];
            }
        }
    }

    static void PrintArray(int[] arr)
    {
        foreach (int item in arr)
        {
            Console.Write(item + " ");
        }
        Console.WriteLine();
    }

    static void PrintArray(int[,] arr)
    {
        int rowCount = arr.GetLength(0);
        int colCount = arr.GetLength(1);

        for (int i = 0; i < rowCount; i++)
        {
            for (int j = 0; j < colCount; j++)
            {
                Console.Write(arr[i, j] + " ");
            }
            Console.WriteLine();
        }
    }
}
```

This program defines two overloaded `RemoveAllOccurrences` methods, one for one-dimensional arrays and another for two-dimensional arrays. These methods use a two-pointer approach to efficiently remove all occurrences of the specified item in-place. The `Array.Resize` method is used to resize the array to the new length after the removal operation.

The program also includes `PrintArray` methods to display the arrays before and after the removal operation.

