import java.util.Scanner;

public class FibonacciSequence {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        int min, max;
        do {
            System.out.print("Enter the minimum value of the range: ");
            min = scanner.nextInt();
            System.out.print("Enter the maximum value of the range: ");
            max = scanner.nextInt();

            if (max <= min) {
                System.out.println("Invalid input! Maximum value must be greater than the minimum value. Please try again.");
            }
        } while (max <= min);

        System.out.println("Fibonacci sequence within the given range:");
        int sum = 0;
        int fib1 = 0;
        int fib2 = 1;
        int fibonacci = 0;

        while (fibonacci <= max) {
            if (fibonacci >= min) {
                System.out.print(fibonacci + " ");
                sum += fibonacci;
            }
            fibonacci = fib1 + fib2;
            fib1 = fib2;
            fib2 = fibonacci;
        }

        System.out.println("\nSum of the Fibonacci sequence: " + sum);
    }
}
```

