import React, { useState, useEffect } from 'react';
import { View, Text, TextInput, FlatList, TouchableOpacity } from 'react-native';
import axios from 'axios';

const API_KEY = 'YOUR_NEWS_API_KEY';

const App = () => {
  const [articles, setArticles] = useState([]);
  const [searchText, setSearchText] = useState('');
  const [categoryFilter, setCategoryFilter] = useState('');

  useEffect(() => {
    fetchArticles();
  }, []);

  const fetchArticles = async () => {
    try {
      const response = await axios.get(`https://newsapi.org/v2/top-headlines?country=us&apiKey=${API_KEY}`);
      setArticles(response.data.articles);
    } catch (error) {
      console.error(error);
    }
  };

  const searchArticles = () => {
    if (searchText === '') {
      fetchArticles();
    } else {
      const filteredArticles = articles.filter(article =>
        article.title.toLowerCase().includes(searchText.toLowerCase())
      );
      setArticles(filteredArticles);
    }
  };

  const filterArticles = (category) => {
    if (category === categoryFilter) {
      setCategoryFilter('');
      fetchArticles();
    } else {
      const filteredArticles = articles.filter(article =>
        article.category === category
      );
      setArticles(filteredArticles);
      setCategoryFilter(category);
    }
  };

  const renderArticle = ({ item }) => (
    <TouchableOpacity style={{ padding: 10 }}>
      <Text style={{ fontWeight: 'bold', fontSize: 16 }}>{item.title}</Text>
      <Text>{item.description}</Text>
      <Text style={{ fontStyle: 'italic', marginTop: 5 }}>{item.source.name}</Text>
      <Text style={{ marginTop: 5 }}>{item.publishedAt}</Text>
      <View style={{ height: 1, backgroundColor: 'lightgray', marginVertical: 10 }} />
    </TouchableOpacity>
  );

  return (
    <View style={{ flex: 1, padding: 10 }}>
      <TextInput
        style={{ height: 40, borderColor: 'gray', borderWidth: 1, marginBottom: 10, paddingHorizontal: 10 }}
        placeholder="Search by title"
        value={searchText}
        onChangeText={text => setSearchText(text)}
        onSubmitEditing={searchArticles}
      />

      <View style={{ flexDirection: 'row', justifyContent: 'space-between', marginBottom: 10 }}>
        <TouchableOpacity onPress={() => filterArticles('business')}>
          <Text style={{ fontWeight: categoryFilter === 'business' ? 'bold' : 'normal' }}>Business</Text>
        </TouchableOpacity>
        <TouchableOpacity onPress={() => filterArticles('sports')}>
