          <Text style={{ fontWeight: categoryFilter === 'entertainment' ? 'bold' : 'normal' }}>Entertainment</Text>
        </TouchableOpacity>
      </View>

      <FlatList
        data={articles}
        renderItem={renderArticle}
        keyExtractor={item => item.title}
      />
    </View>
  );
};

export default App;
