    public static int[] deleteDuplicates(int[] arr) {
        int n = arr.length;

        // Iterate through the array and mark the presence of each element
        for (int i = 0; i < n; i++) {
            int num = Math.abs(arr[i]);
            if (arr[num] > 0) {
                arr[num] = -arr[num];
            }
        }

        // Count the number of unique elements
        int count = 0;
        for (int i = 0; i < n; i++) {
            if (arr[i] < 0) {
                count++;
            }
        }

        // Create a new array to store the unique elements
