```
public class MyClass {
    private int attribute;

    public MyClass(int attribute) {
        this.attribute = attribute;
    }

    public int getAttribute() {
        return attribute;
    }

    public void setAttribute(int attribute) {
        this.attribute = attribute;
    }
}

public class MergeSort {
    public static void main(String[] args) {
        MyClass[] array = {new MyClass(23), new MyClass(10), new MyClass(4), new MyClass(15), new MyClass(66), new MyClass(28), new MyClass(11)};

        mergeSort(array, 0, array.length - 1);

        for (MyClass obj : array) {
            System.out.println(obj.getAttribute());
        }
    }

    public static void mergeSort(MyClass[] array, int left, int right) {
        if (left < right) {
            int middle = (left + right) / 2;

            mergeSort(array, left, middle);
            mergeSort(array, middle + 1, right);

            merge(array, left, middle, right);
        }
    }

    public static void merge(MyClass[] array, int left, int middle, int right) {
        int n1 = middle - left + 1;
        int n2 = right - middle;

        MyClass[] leftArray = new MyClass[n1];
        MyClass[] rightArray = new MyClass[n2];

        for (int i = 0; i < n1; i++) {
            leftArray[i] = array[left + i];
        }
        for (int i = 0; i < n2; i++) {
            rightArray[i] = array[middle + 1 + i];
        }

        int i = 0;
        int j = 0;
        int k = left;

        while (i < n1 && j < n2) {
            if (leftArray[i].getAttribute() <= rightArray[j].getAttribute()) {
                array[k] = leftArray[i];
                i++;
            } else {
                array[k] = rightArray[j];
                j++;
            }
            k++;
        }

        while (i < n1) {
            array[k] = leftArray[i];
            i++;
            k++;
        }

        while (j < n2) {
            array[k] = rightArray[j];
            j++;
            k++;
        }
    }
}
```

This implementation uses the Merge Sort algorithm, which has a time complexity of O(nlogn) and is a comparison-based sorting algorithm. It sorts the array in place and retains the relative order of objects with equal integer attributes.

