            System.out.println("Matrix Multiplication Result:");
            for (int i = 0; i < result.length; i++) {
                for (int j = 0; j < result[0].length; j++) {
                    System.out.print(result[i][j] + " ");
                }
                System.out.println();
            }
        }
    }

    public static int[][] multiplyMatrix(int[][] A, int[][] B) {
        if (A == null || B == null) {
            System.out.println("Invalid input: Matrices cannot be null.");
            return null;
        }

        int m = A.length;
        int n = A[0].length;
        int p = B.length;
        int q = B[0].length;

        if (n != p) {
            System.out.println("Invalid input: Matrices cannot be multiplied due to incompatible sizes.");
            return null;
        }

        if (m <= 0 || n <= 0 || p <= 0 || q <= 0) {
            System.out.println("Invalid input: Matrices cannot have negative dimensions.");
            return null;
        }

        int[][] result = new int[m][q];
        multiplyMatrixRecursive(A, B, result, 0, 0, 0, 0, m, n, p, q);
        return result;
    }

    public static void multiplyMatrixRecursive(int[][] A, int[][] B, int[][] result,
            int startRowA, int startColA, int startRowB, int startColB,
            int m, int n, int p, int q) {

        if (m == 1 && n == 1 && p == 1 && q == 1) {
            result[startRowA][startColB] ^= A[startRowA][startColA] & B[startRowB][startColB];
            return;
        }

        int midRowA = startRowA + (m / 2);
        int midColA = startColA + (n / 2);
        int midRowB = startRowB + (n / 2);
        int midColB = startColB + (q / 2);

        multiplyMatrixRecursive(A, B, result, startRowA, startColA, startRowB, startColB, m / 2, n / 2, p / 2, q / 2);
        multiplyMatrixRecursive(A, B, result, startRowA, midColA, midRowB, startColB, m / 2, n - (n / 2), p / 2, q / 2);
        multiplyMatrixRecursive(A, B, result, startRowA, startColA, startRowB, midColB, m / 2, n / 2, p / 2, q - (q / 2));
        multiplyMatrixRecursive(A, B, result, startRowA, midColA, midRowB, midColB, m / 2, n - (n / 2), p / 2, q - (q / 2));
        multiplyMatrixRecursive(A, B, result, midRowA, startColA, startRowB, startColB, m - (m / 2), n / 2, p / 2, q / 2);
        multiplyMatrixRecursive(A, B, result, midRowA, midColA, midRowB, startColB, m - (m / 2), n - (n / 2), p / 2, q / 2);
        multiplyMatrixRecursive(A, B, result, midRowA, startColA, startRowB, midColB, m - (m / 2), n / 2, p / 2, q - (q / 2));
        multiplyMatrixRecursive(A, B, result, midRowA, midColA, midRowB, midColB, m - (m / 2), n - (n / 2), p / 2, q - (q / 2));
    }
}
```

