    if number < 2:
        return False

    for i in range(2, int(math.sqrt(number)) + 1):
        if number % i == 0:
            return False

    return True

def prime_factors(number):
    factors = []

    for i in range(2, int(math.sqrt(number)) + 1):
        while number % i == 0:
            factors.append(i)
            number = number // i

    if number > 1:
        factors.append(number)

    return factors

