        return current_time.strftime('%Y-%m-%d %I:%M:%S %p')
    else:
        return current_time.strftime('%Y-%m-%d %H:%M:%S')

def get_remaining_time(scheduled_time):
    current_time = datetime.datetime.now()
    remaining_time = scheduled_time - current_time
    return remaining_time.total_seconds()

def update_content(timezones, time_format):
    for timezone in timezones:
        try:
            current_time = get_current_time(timezone, time_format)
            print(f"Current time in {timezone}: {current_time}")
        except pytz.UnknownTimeZoneError:
            print(f"Invalid timezone: {timezone}")

def schedule_update(timezones, time_format, scheduled_time):
    try:
        scheduled_time = datetime.datetime.strptime(scheduled_time, '%Y-%m-%d %H:%M:%S')
        remaining_time = get_remaining_time(scheduled_time)
        if remaining_time > 0:
            print(f"Updating content in {remaining_time} seconds.")
        else:
            print("Scheduled time has already passed.")
            return
    except ValueError:
        print("Invalid date format.")
        return

