2. Create a `server.js` file and add the following code:

```javascript
const express = require('express');
const app = express();
const pgp = require('pg-promise')();
const db = pgp('postgres://username:password@localhost:5432/database_name');
const { Validator } = require('jsonschema');
const validator = new Validator();

// Define the JSON schema
const schema = {
  type: 'object',
  properties: {
    name: { type: 'string' },
    age: { type: 'number' },
    email: { type: 'string', format: 'email' }
  },
  required: ['name', 'age', 'email']
};

// Middleware to parse JSON data
app.use(express.json());

// Endpoint to accept JSON data
app.post('/data', (req, res) => {
  const data = req.body;

  // Validate the JSON data against the schema
  const validationResult = validator.validate(data, schema);

  if (!validationResult.valid) {
    const errors = validationResult.errors.map((error) => error.stack);
    return res.status(400).json({ errors });
  }

  // Insert the data into the PostgreSQL database
  db.none('INSERT INTO your_table(name, age, email) VALUES($1, $2, $3)', [data.name, data.age, data.email])
    .then(() => {
      res.sendStatus(200);
    })
    .catch((error) => {
      console.error('Error inserting data:', error);
      res.sendStatus(500);
    });
});

// Error handler for database connection errors
db.connect()
  .then(() => {
    app.listen(3000, () => {
      console.log('Server started on port 3000');
    });
  })
  .catch((error) => {
    console.error('Error connecting to database:', error);
  });
```

Replace `'postgres://username:password@localhost:5432/database_name'` with your PostgreSQL connection string. Replace `'your_table'` with the name of your table in the database.

This API will listen on `http://localhost:3000/data` and accept a `POST` request with JSON data. It will validate the JSON data against the specified schema and insert it into the PostgreSQL database if valid. If any errors occur during the validation or database insertion, appropriate error messages will be sent to the client.

