import random

def predict_next_letter(pattern, text):
    occurrences = []
    for i in range(len(text) - len(pattern)):
        if text[i:i+len(pattern)] == pattern:
            occurrences.append(text[i+len(pattern)])

    if len(occurrences) == 0:
        return "Pattern not found"

    frequencies = {}
    for letter in occurrences:
        if letter in frequencies:
            frequencies[letter] += 1
        else:
            frequencies[letter] = 1

    max_frequency = max(frequencies.values())
    predicted_letters = [letter for letter, freq in frequencies.items() if freq == max_frequency]

    return random.choice(predicted_letters)

