function calculate(num1, num2, operator) {
  // Check if either number is a complex number
  if (typeof num1 === 'string' || typeof num2 === 'string') {
    // Parse the complex numbers
    const complex1 = parseComplexNumber(num1);
    const complex2 = parseComplexNumber(num2);

    // Perform the operation on the complex numbers
    switch (operator) {
      case '+':
        return complexAdd(complex1, complex2);
      case '-':
        return complexSubtract(complex1, complex2);
      case '*':
        return complexMultiply(complex1, complex2);
      case '/':
        return complexDivide(complex1, complex2);
      case '%':
        return complexModulo(complex1, complex2);
      default:
        return "Invalid operator";
    }
  } else {
    // Perform the operation on the real numbers
    switch (operator) {
      case '+':
        return num1 + num2;
      case '-':
        return num1 - num2;
      case '*':
        return num1 * num2;
      case '/':
        return num1 / num2;
      case '%':
        return num1 % num2;
      default:
        return "Invalid operator";
    }
  }
}

function parseComplexNumber(num) {
  // Split the complex number into real and imaginary parts
  const parts = num.split('+');
  const real = parseFloat(parts[0]);
  const imaginary = parseFloat(parts[1]);

  // Return an object representing the complex number
  return { real, imaginary };
}

function complexAdd(num1, num2) {
  // Perform addition on the real and imaginary parts separately
  const real = num1.real + num2.real;
  const imaginary = num1.imaginary + num2.imaginary;

  // Return the result as a complex number
  return complexToString(real, imaginary);
}

function complexSubtract(num1, num2) {
  // Perform subtraction on the real and imaginary parts separately
  const real = num1.real - num2.real;
  const imaginary = num1.imaginary - num2.imaginary;

  // Return the result as a complex number
  return complexToString(real, imaginary);
}

function complexMultiply(num1, num2) {
  // Perform multiplication on the real and imaginary parts separately
  const real = num1.real * num2.real - num1.imaginary * num2.imaginary;
  const imaginary = num1.real * num2.imaginary + num1.imaginary * num2.real;

  // Return the result as a complex number
  return complexToString(real, imaginary);
}

function complexDivide(num1, num2) {
  // Calculate the divisor
  const divisor = num2.real * num2.real + num2.imaginary * num2.imaginary;

  // Perform division on the real and imaginary parts separately
  const real = (num1.real * num2.real + num1.imaginary * num2.imaginary) / divisor;
  const imaginary = (num1.imaginary * num2.real - num1.real * num2.imaginary) / divisor;

  // Return the result as a complex number
  return complexToString(real, imaginary);
}

function complexModulo(num1, num2) {
  // Calculate the divisor
  const divisor = num2.real * num2.real + num2.imaginary * num2.imaginary;

  // Perform modulo on the real and imaginary parts separately
  const real = ((num1.real * num2.real + num1.imaginary * num2.imaginary) % divisor + divisor) % divisor;
  const imaginary = ((num1.imaginary * num2.real - num1.real * num2.imaginary) % divisor + divisor) % divisor;

  // Return the result as a complex number
  return complexToString(real, imaginary);
}

function complexToString(real, imaginary) {
  // Format the complex number as a string
  return real + '+' + imaginary + 'i';
}
```

