```typescript
import { Injectable } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Observable, BehaviorSubject } from 'rxjs';
import { tap } from 'rxjs/operators';

@Injectable({
  providedIn: 'root'
})
export class AuthService {
  private accessToken: string;
  private refreshToken: string;
  private accessTokenExpiration: Date;
  private refreshTokenExpiration: Date;
  private refreshTokenSubject: BehaviorSubject<string> = new BehaviorSubject<string>(null);

  constructor(private http: HttpClient) { }

  login(username: string, password: string): Observable<any> {
    return this.http.post<any>('api/auth/login', { username, password })
      .pipe(
        tap(response => {
          this.setTokens(response.accessToken, response.refreshToken);
          this.startRefreshTokenTimer();
        })
      );
  }

  logout() {
    this.clearTokens();
  }

  refreshTokenIfNeeded(): Observable<any> {
    if (!this.accessToken || new Date() >= this.accessTokenExpiration) {
      if (this.refreshToken && new Date() >= this.refreshTokenExpiration) {
        this.clearTokens();
        return Observable.throw('Refresh token expired');
      } else {
        return this.refreshTokenRequest()
          .pipe(
            tap(response => {
              this.setTokens(response.accessToken, response.refreshToken);
              this.startRefreshTokenTimer();
            })
          );
      }
    } else {
      return Observable.of(null);
    }
  }

  private refreshTokenRequest(): Observable<any> {
    return this.http.post<any>('api/auth/refresh-token', { refreshToken: this.refreshToken });
  }

  private setTokens(accessToken: string, refreshToken: string) {
    this.accessToken = accessToken;
    this.refreshToken = refreshToken;
    this.accessTokenExpiration = this.getTokenExpirationDate(accessToken);
    this.refreshTokenExpiration = this.getTokenExpirationDate(refreshToken);
    this.refreshTokenSubject.next(this.accessToken);
  }

  private clearTokens() {
    this.accessToken = null;
    this.refreshToken = null;
    this.accessTokenExpiration = null;
    this.refreshTokenExpiration = null;
    this.refreshTokenSubject.next(null);
  }

  private getTokenExpirationDate(token: string): Date {
    const decodedToken = JSON.parse(atob(token.split('.')[1]));
    if (decodedToken && decodedToken.exp) {
      return new Date(decodedToken.exp * 1000);
    }
    return null;
  }

  private startRefreshTokenTimer() {
    const expirationTime = this.accessTokenExpiration.getTime() - Date.now() - (60 * 1000); // Refresh 1 minute before expiration
    setTimeout(() => {
      this.refreshTokenIfNeeded().subscribe();
    }, expirationTime);
  }

  getAccessToken(): string {
    return this.accessToken;
  }

  getAccessTokenObservable(): Observable<string> {
    return this.refreshTokenSubject.asObservable();
  }
}
```

In this example, the `AuthService` class handles the login, logout, and token refresh functionalities. It uses `HttpClient` to make HTTP requests to the API endpoints for authentication.

When the user logs in (`login` method), the service stores the access token and refresh token and starts a timer to automatically refresh the access token just before it expires.

The `refreshTokenIfNeeded` method is used to check if the access token is expired or not. If it is expired, it checks if the refresh token is also expired. If the refresh token is expired, it clears the tokens and throws an error. Otherwise, it makes a refresh token request to get a new access token and refresh token, updates the tokens, and starts a new refresh token timer.

The service also provides methods to get the current access token (`getAccessToken`) and an observable that emits the access token whenever it is refreshed (`getAccessTokenObservable`).

Note: This is just an example implementation, and it assumes that the API endpoints `api/auth/login` and `api/auth/refresh-token` are available and properly implemented on the server side. You may need to modify the code to fit your specific authentication API.

