Here's a Swift code implementation to find all prime numbers within a given range of numbers:

```swift
import Foundation

func isPrime(_ number: Int) -> Bool {
    if number <= 1 {
        return false
    }

    if number <= 3 {
        return true
    }

    if number % 2 == 0 || number % 3 == 0 {
        return false
    }

    var i = 5
    while i * i <= number {
        if number % i == 0 || number % (i + 2) == 0 {
            return false
        }
        i += 6
    }

    return true
}

func findPrimesInRange(_ start: Int, _ end: Int) -> [Int] {
    var primes = [Int]()

    for number in start...end {
        if isPrime(number) {
            primes.append(number)
        }
    }

    return primes
}

// Example usage
