public class FibonacciSequence {
    private static final int MAX_VALUE = 1000;
    private static final int SIZE = 10;

    public static void main(String[] args) {
        int[] fibNumbers = new int[SIZE];
        for (int i = 0; i < SIZE; i++) {
            int fibNumber = fibonacci(i);
            fibNumbers[i] = fibNumber;
            System.out.println(fibNumber + " - " + (isPrime(fibNumber) ? "Prime" : "Not Prime"));
        }
        System.out.println("\nReversed Fibonacci Sequence:");
        for (int i = SIZE - 1; i >= 0; i--) {
            System.out.print(fibNumbers[i] + " ");
        }
    }

    private static int fibonacci(int n) {
        if (n == 0) return 0;
        if (n == 1 || n == 2) return 1;
        int[][] matrix = { {1, 1}, {1, 0} };
        matrix = power(matrix, n - 1);
        return matrix[0][0];
    }

    private static int[][] power(int[][] matrix, int n) {
        if (n == 1) return matrix;
        int[][] result = power(matrix, n / 2);
        result = multiply(result, result);
        if (n % 2 == 1) {
            result = multiply(result, matrix);
        }
        return result;
    }

    private static int[][] multiply(int[][] matrix1, int[][] matrix2) {
        int rows1 = matrix1.length;
        int cols1 = matrix1[0].length;
        int cols2 = matrix2[0].length;
        int[][] result = new int[rows1][cols2];
        for (int i = 0; i < rows1; i++) {
            for (int j = 0; j < cols2; j++) {
                for (int k = 0; k < cols1; k++) {
                    result[i][j] += matrix1[i][k] * matrix2[k][j];
                }
            }
        }
        return result;
    }

    private static boolean isPrime(int num) {
        if (num < 2) return false;
        for (int i = 2; i <= Math.sqrt(num); i++) {
            if (num % i == 0) return false;
        }
        return true;
    }
}
```

