```java
import java.util.Scanner;

public class PrimeFactorsSum {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        // Read the first number
        System.out.print("Enter the first positive prime number: ");
        int num1 = scanner.nextInt();

        // Check if the first number is prime
        if (!isPrime(num1)) {
            System.out.println("Input is not a prime number. Program terminated.");
            System.exit(0);
        }

        // Read the second number
        System.out.print("Enter the second positive prime number: ");
        int num2 = scanner.nextInt();

        // Check if the second number is prime
        if (!isPrime(num2)) {
            System.out.println("Input is not a prime number. Program terminated.");
            System.exit(0);
        }

        // Calculate and print the sum of prime factors
        int sum = sumOfPrimeFactors(num1) + sumOfPrimeFactors(num2);
        System.out.println("Sum of prime factors: " + sum);

        scanner.close();
    }

    // Function to check if a number is prime
    public static boolean isPrime(int number) {
        if (number <= 1) {
            return false;
        }

        for (int i = 2; i <= Math.sqrt(number); i++) {
            if (number % i == 0) {
                return false;
            }
        }

        return true;
    }

    // Function to calculate the sum of prime factors of a number
    public static int sumOfPrimeFactors(int number) {
        int sum = 0;

        for (int i = 2; i <= number; i++) {
            if (number % i == 0 && isPrime(i)) {
                sum += i;
            }
        }

        return sum;
    }
}
```

