const app = express();
const port = 3000;

// MongoDB connection
mongoose.connect('mongodb://localhost:27017/allowed_ips', {
  useNewUrlParser: true,
  useUnifiedTopology: true,
});
const allowedIPSchema = new mongoose.Schema({
  ip: String,
});
const AllowedIP = mongoose.model('AllowedIP', allowedIPSchema);

// Middleware to check allowed IP addresses
const checkAllowedIP = async (req, res, next) => {
  const { ip } = req.headers;
  const allowedIPs = await AllowedIP.find({});
  const allowedIPAddresses = allowedIPs.map((allowedIP) => allowedIP.ip);

  if (!allowedIPAddresses.includes(ip)) {
    return res.status(403).json({ error: 'Access Denied' });
  }

  next();
};

// Routes
app.get('/', checkAllowedIP, (req, res) => {
  const currentDateTime = new Date().toISOString().replace('T', ' ').substr(0, 19);
  res.send(`Current Date and Time: ${currentDateTime}`);
});

// Error handling middleware
app.use((err, req, res, next) => {
  console.error(err.stack);
  res.status(500).json({ error: 'Internal Server Error' });
});

// Start the server
app.listen(port, () => {
  console.log(`Server is running on http://localhost:${port}`);
});
```

