import java.util.ArrayList;
import java.util.Date;
import java.util.List;

public class BankAccount {
    private String accountNumber;
    private String name;
    private double balance;
    private List<Transaction> transactionHistory;

    public BankAccount(String accountNumber, String name) {
        this.accountNumber = accountNumber;
        this.name = name;
        this.balance = 0.0;
        this.transactionHistory = new ArrayList<>();
    }

    public void deposit(double amount) throws IllegalArgumentException {
        if (amount <= 0) {
            throw new IllegalArgumentException("Deposit amount must be positive.");
        }
        this.balance += amount;
        Transaction transaction = new Transaction(new Date(), amount, "Deposit", this.balance);
        this.transactionHistory.add(transaction);
    }

    public void withdraw(double amount) throws IllegalArgumentException {
        if (amount <= 0) {
            throw new IllegalArgumentException("Withdrawal amount must be positive.");
        }
        if (amount > this.balance) {
            throw new IllegalArgumentException("Insufficient funds.");
        }
        this.balance -= amount;
        Transaction transaction = new Transaction(new Date(), amount, "Withdrawal", this.balance);
        this.transactionHistory.add(transaction);
    }

    public double calculateInterest(double interestRate) {
        double interest = this.balance * interestRate;
        return interest;
    }

    public void transfer(BankAccount receiver, double amount, double transactionFee) throws IllegalArgumentException {
        if (amount <= 0) {
            throw new IllegalArgumentException("Transfer amount must be positive.");
        }
        if (!Bank.isAccountExists(receiver)) {
            throw new IllegalArgumentException("Receiver account does not exist.");
        }
        if (this.balance < amount + transactionFee) {
            throw new IllegalArgumentException("Insufficient funds.");
        }
        this.balance -= amount + transactionFee;
        receiver.balance += amount;
        Transaction senderTransaction = new Transaction(new Date(), amount, "Transfer Sent", this.balance);
        Transaction receiverTransaction = new Transaction(new Date(), amount, "Transfer Received", receiver.balance);
        this.transactionHistory.add(senderTransaction);
        receiver.transactionHistory.add(receiverTransaction);
    }

    public String getAccountNumber() {
        return accountNumber;
    }

    public String getName() {
        return name;
    }

    public double getBalance() {
        return balance;
    }

    public List<Transaction> getTransactionHistory() {
        return transactionHistory;
    }
}

class Transaction {
    private Date date;
    private double amount;
    private String type;
    private double balanceAfterTransaction;

    public Transaction(Date date, double amount, String type, double balanceAfterTransaction) {
        this.date = date;
        this.amount = amount;
        this.type = type;
        this.balanceAfterTransaction = balanceAfterTransaction;
    }

    public Date getDate() {
        return date;
    }

    public double getAmount() {
        return amount;
    }

    public String getType() {
        return type;
    }

    public double getBalanceAfterTransaction() {
        return balanceAfterTransaction;
    }
}

class Bank {
    private List<BankAccount> accounts;

    public Bank() {
        this.accounts = new ArrayList<>();
    }

    public void addAccount(BankAccount account) {
        this.accounts.add(account);
    }

    public boolean isAccountExists(BankAccount account) {
        return this.accounts.contains(account);
    }
}
