Here's a JavaScript code that generates a random array of 1000 integers, sorts the array in descending order, and removes any duplicate values from the array:

```javascript
// Generate a random array of 1000 integers
function generateRandomArray() {
  let arr = [];
  for (let i = 0; i < 1000; i++) {
    arr.push(Math.floor(Math.random() * 1000));
  }
  return arr;
}

// Sort the array in descending order
function sortArrayDescending(arr) {
  for (let i = 0; i < arr.length - 1; i++) {
    for (let j = 0; j < arr.length - i - 1; j++) {
      if (arr[j] < arr[j + 1]) {
        let temp = arr[j];
        arr[j] = arr[j + 1];
        arr[j + 1] = temp;
      }
    }
  }
  return arr;
}

// Remove duplicate values from the array
function removeDuplicates(arr) {
  let uniqueArr = [];
  for (let i = 0; i < arr.length; i++) {
    let duplicate = false;
    for (let j = 0; j < uniqueArr.length; j++) {
      if (arr[i] === uniqueArr[j]) {
        duplicate = true;
        break;
      }
    }
    if (!duplicate) {
      uniqueArr.push(arr[i]);
    }
  }
  return uniqueArr;
}

// Generate a random array of 1000 integers
let arr = generateRandomArray();

// Sort the array in descending order
arr = sortArrayDescending(arr);

// Remove duplicate values from the array
arr = removeDuplicates(arr);

console.log(arr);
```

Note that the sorting algorithm used here is Bubble Sort, which has a time complexity of O(n^2). The removeDuplicates function also has a time complexity of O(n^2) as it uses nested loops.

