```java
public class DayOfWeekCalculator {

    private static final String[] DAYS_OF_WEEK = {"Sunday", "Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday"};

    private static final int[] MONTH_OFFSETS = {0, 3, 3, 6, 1, 4, 6, 2, 5, 0, 3, 5};

    public static void main(String[] args) {
        int day = 15;
        int month = 9;
        int year = 2022;

        int dayOfWeek = calculateDayOfWeek(day, month, year);
        System.out.println("The day of the week is: " + DAYS_OF_WEEK[dayOfWeek]);
    }

    public static int calculateDayOfWeek(int day, int month, int year) {
        int century = year / 100;
        int centuryOffset = (3 - (century % 4)) * 2;

        int yearOffset = (year % 100) / 4;

        int monthOffset = MONTH_OFFSETS[month - 1];
        if (isLeapYear(year) && (month == 1 || month == 2)) {
            monthOffset -= 1;
        }

        int dayOfWeek = (centuryOffset + yearOffset + monthOffset + day) % 7;
        return dayOfWeek;
    }

    public static boolean isLeapYear(int year) {
        if (year % 4 != 0) {
            return false;
        } else if (year % 100 != 0) {
            return true;
        } else if (year % 400 != 0) {
            return false;
        } else {
            return true;
        }
    }
}
```

