public class Counter {
    private int value;

    public int get() {
        return value;
    }

    public void increment() {
        if (value < 1000) {
            value++;
        } else {
            System.out.println("Error: Counter cannot exceed 1000.");
        }
    }

    public void decrement() {
        if (value > -1000) {
            value--;
        } else {
            System.out.println("Error: Counter cannot go below -1000.");
        }
    }

    public void add(int num) {
        if (value + num <= 1000 && value + num >= -1000) {
            value += num;
        } else {
            System.out.println("Error: Counter value out of range.");
        }
    }

    public void subtract(int num) {
        if (value - num <= 1000 && value - num >= -1000) {
            value -= num;
        } else {
            System.out.println("Error: Counter value out of range.");
        }
    }

    public void reset() {
        value = 0;
    }

    public String getFormattedValue() {
        return "Counter value: " + value + " (Acceptable range: -1000 to 1000)";
    }
}
```

