```javascript
function findFirstPrimes(arr, k = 1) {
  const primes = [];
  const isPrime = (num) => {
    if (num < 2) return false;
    for (let i = 2; i <= Math.sqrt(num); i++) {
      if (num % i === 0) return false;
    }
    return true;
  };

  for (let i = 0; i < arr.length && primes.length < k; i++) {
    const num = arr[i];
    if (isPrime(num) && !primes.includes(num)) {
      primes.push(num);
    }
  }

  if (primes.length === 0 || k <= 0) {
    return [];
  } else if (k === 1) {
    return primes[0];
  } else {
    return primes.slice(0, k);
  }
}
```

