Here's a program in Python that uses a recursive approach to find the nth prime number in the Fibonacci sequence and calculates the sum of all prime numbers up to that number:

```python
def is_prime(n):
    if n <= 1:
        return False
    if n <= 3:
        return True
    if n % 2 == 0 or n % 3 == 0:
        return False
    i = 5
    while i * i <= n:
        if n % i == 0 or n % (i + 2) == 0:
            return False
        i += 6
    return True

def fibonacci(n):
    if n <= 0:
        return 0
    if n == 1:
        return 1
    return fibonacci(n-1) + fibonacci(n-2)

def nth_prime_fibonacci(n):
    count = 0
    i = 0
    sum_primes = 0
    while count < n:
        fib_num = fibonacci(i)
        if is_prime(fib_num):
            sum_primes += fib_num
            count += 1
        i += 1
    return sum_primes

