```java
import java.util.Arrays;

public class StringOperations {

    public static String addString(String str1, String str2) {
        // Convert all vowels to uppercase and consonants to lowercase
        str1 = str1.toLowerCase().replaceAll("[aeiou]", String::toUpperCase);
        str2 = str2.toLowerCase().replaceAll("[aeiou]", String::toUpperCase);

        // Concatenate the two strings
        String result = str1 + str2;

        // Remove duplicate characters
        result = removeDuplicates(result);

        // Sort the characters in ascending order
        char[] chars = result.toCharArray();
        Arrays.sort(chars);
        result = new String(chars);

        // Move uppercase characters before lowercase characters
        StringBuilder sb = new StringBuilder(result);
        int i = 0;
        int j = result.length() - 1;
        while (i < j) {
            if (Character.isLowerCase(sb.charAt(i)) && Character.isUpperCase(sb.charAt(j))) {
                char temp = sb.charAt(i);
                sb.setCharAt(i, sb.charAt(j));
                sb.setCharAt(j, temp);
                i++;
                j--;
            } else {
                if (Character.isLowerCase(sb.charAt(i))) {
                    i++;
                }
                if (Character.isUpperCase(sb.charAt(j))) {
                    j--;
                }
            }
        }
        result = sb.toString();

        return result;
    }

    // Helper method to remove duplicate characters
    private static String removeDuplicates(String str) {
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < str.length(); i++) {
            if (sb.indexOf(String.valueOf(str.charAt(i))) == -1) {
                sb.append(str.charAt(i));
            }
        }
        return sb.toString();
    }

    public static void main(String[] args) {
        String str1 = "abcde";
        String str2 = "cdefg";
        String result = addString(str1, str2);
        System.out.println(result);  // Output: ACDEFGb

        str1 = "Hello";
        str2 = "World";
        result = addString(str1, str2);
        System.out.println(result);  // Output: DLORWHel
    }
}
