Here is an implementation of a basic calculator in C++ that supports addition, subtraction, multiplication, division, parentheses, and exponentiation:

```cpp
#include <iostream>
#include <stack>
#include <cmath>
#include <sstream>

using namespace std;

int getPrecedence(char op) {
    if (op == '^') {
        return 3;
    } else if (op == '*' || op == '/') {
        return 2;
    } else if (op == '+' || op == '-') {
        return 1;
    }
    return 0;
}

double applyOperation(double a, double b, char op) {
    switch (op) {
        case '+': return a + b;
        case '-': return a - b;
        case '*': return a * b;
        case '/': return a / b;
        case '^': return pow(a, b);
    }
    return 0;
}

double evaluateExpression(const string& expression) {
    stack<double> values;
    stack<char> operators;
    stringstream ss(expression);
    string token;

    while (getline(ss, token, ' ')) {
        if (token.empty()) {
            continue;
        }

        if (isdigit(token[0])) {
            double value;
            stringstream(token) >> value;
            values.push(value);
        } else if (token[0] == '(') {
            operators.push('(');
        } else if (token[0] == ')') {
            while (!operators.empty() && operators.top() != '(') {
                double b = values.top();
                values.pop();

                double a = values.top();
                values.pop();

                char op = operators.top();
                operators.pop();

                values.push(applyOperation(a, b, op));
            }

            if (!operators.empty()) {
                operators.pop();
            }
        } else {
            while (!operators.empty() && getPrecedence(operators.top()) >= getPrecedence(token[0])) {
                double b = values.top();
                values.pop();

                double a = values.top();
                values.pop();

                char op = operators.top();
                operators.pop();

                values.push(applyOperation(a, b, op));
            }

            operators.push(token[0]);
        }
    }

    while (!operators.empty()) {
        double b = values.top();
        values.pop();

        double a = values.top();
        values.pop();

        char op = operators.top();
        operators.pop();

        values.push(applyOperation(a, b, op));
    }

    return values.top();
}

int main() {
    string expression = "2 * (3 + 4) - 5 ^ 2";
    double result = evaluateExpression(expression);

    cout << "Result: " << result << endl;

    return 0;
}
