```javascript
function greetUser(name) {
  // Check if the name is empty or consists of whitespace characters
  if (name.trim().length === 0) {
    throw new Error('Invalid name');
  }

  // Remove any special characters and convert the name to lowercase
  const normalized = name.replace(/[^a-zA-Z]/g, '').toLowerCase();

  // Check if the normalized name is a palindrome
  let isPalindrome = true;
  for (let i = 0, j = normalized.length - 1; i < j; i++, j--) {
    if (normalized[i] !== normalized[j]) {
      isPalindrome = false;
      break;
    }
  }

  // Greet the user and return the appropriate message
  if (isPalindrome) {
    return `Hello, ${name}! Your name is a palindrome.`;
  } else {
    return `Hello, ${name}!`;
  }
}
```

