    def validate_password(self, password):
        if len(password) < 12:
            return False
        if not any(char.isupper() for char in password):
            return False
        if not any(char.islower() for char in password):
            return False
        if not any(char.isdigit() for char in password):
            return False
        if not any(char in '!@#$%^&*' for char in password):
            return False
        if password == 'password' or password == '123456':
            return False
        return True

    def changePassword(self, new_password):
        if self.validate_password(new_password):
            self.password = new_password
            print("Password changed successfully!")
        else:
            print("Invalid password format!")

    def resetPassword(self):
        random_password = ''.join(random.choice(string.ascii_letters + string.digits + '!@#$%^&*') for _ in range(12))
        if self.validate_password(random_password):
            self.password = random_password
            print("Password reset successfully!")
        else:
            print("Error generating random password!")

    def login(self, username, password):
        if self.is_locked:
            print("Profile is locked. Please contact administrator.")
            return False
        if self.username == username and self.password == password:
            self.failed_login_attempts = 0
            print("Login successful!")
            return True
        else:
            self.failed_login_attempts += 1
            print("Invalid username or password!")
            if self.failed_login_attempts == 3:
                self.is_locked = True
                print("Profile locked due to consecutive failed login attempts.")
            return False

    def unlockProfile(self, admin_password):
        if self.validate_password(admin_password) and admin_password == "AdminPassword123!":
            self.is_locked = False
            print("Profile unlocked successfully!")
        else:
            print("Invalid administrator password!")

    def logout(self):
        self.failed_login_attempts = 0
        print("Logged out successfully!")

