Here is a Java program that finds the longest words from a sentence, ignoring punctuation marks or special characters, and handles cases where there are multiple words with the same length:

```java
import java.util.Arrays;
import java.util.HashSet;

public class LongestWords {
    public static String[] findLongestWords(String sentence) {
        // Remove punctuation marks and special characters
        String cleanSentence = sentence.replaceAll("[^a-zA-Z ]", "");

        // Split the sentence into words
        String[] words = cleanSentence.split(" ");

        // Sort the words in descending order of length
        Arrays.sort(words, (a, b) -> b.length() - a.length());

        // Find the length of the longest word
        int longestLength = words[0].length();

        // Find all the words with the longest length
        HashSet<String> longestWords = new HashSet<>();
        for (String word : words) {
            if (word.length() == longestLength) {
                longestWords.add(word);
            } else {
                break;
            }
        }

        return longestWords.toArray(new String[0]);
    }

    public static void main(String[] args) {
        String sentence = "This is a sample sentence, with some special characters like !@#$%^&*()-=[]{};':,.<>/?|";
        String[] longestWords = findLongestWords(sentence);

        for (String word : longestWords) {
            System.out.println(word);
        }
    }
}
```

