def parse_element(element):
    data = {}
    data['name'] = element.name
    data['text'] = element.text.strip()

    if element.attrs:
        data['attrs'] = element.attrs

    if element.contents:
        data['children'] = []
        for child in element.contents:
            if child.name:
                data['children'].append(parse_element(child))

