function generateTable(schedule) {
  // Create a new table element
  var table = document.createElement("table");

  // Iterate through each day's time slots
  for (var i = 0; i < schedule.length; i++) {
    var day = schedule[i];

    // Create a new table row for each day
    var row = document.createElement("tr");

    // Iterate through each time slot within a day
    for (var j = 0; j < day.length; j++) {
      var timeSlot = day[j];

      // Create a new table cell for each time slot
      var cell = document.createElement("td");

      // Set the text content of the table cell to the corresponding time slot value
      cell.textContent = timeSlot;

      // Append the table cell to the table row
      row.appendChild(cell);
    }

    // Append the table row to the table element
    table.appendChild(row);
  }

  // Append the table element to the document body
  document.body.appendChild(table);
}

