```java
import java.util.Arrays;
import java.util.HashSet;
import java.util.Set;

public class SumOfThreeLargestDistinctValues {
    public static void main(String[] args) {
        int[] array = {3, 8, 4, 16, 1, 7, 7, 4, 8, 8};

        // Convert the array to a set to remove duplicate elements
        Set<Integer> distinctValues = new HashSet<>();
        for (int num : array) {
            distinctValues.add(num);
        }

        // Convert the set back to an array for sorting
        int[] distinctArray = new int[distinctValues.size()];
        int index = 0;
        for (int num : distinctValues) {
            distinctArray[index] = num;
            index++;
        }

        // Sort the array in descending order
        Arrays.sort(distinctArray);
        int sum = 0;

        // Calculate the sum of the three largest distinct values
        for (int i = distinctArray.length - 1; i >= distinctArray.length - 3; i--) {
            sum += distinctArray[i];
        }

        System.out.println("Sum of the three largest distinct values: " + sum);
    }
}
```

The program first converts the array to a set in order to remove duplicate elements. Then, it converts the set back to an array and sorts it in ascending order. Finally, it calculates the sum of the three largest distinct values by iterating from the end of the array and adding the values to the sum.

